import React, { useState, useEffect } from 'react';

const Vegetables = () => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    setIsVisible(true);
  }, []);

  const vegetables = [
    {
      id: 1,
      name: 'Tomato',
      price: '₹20/kg',
      image: 'https://via.placeholder.com/200x200/FF6347/FFFFFF?text=Tomato',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Tomato%20-%20₹20/kg'
    },
    {
      id: 2,
      name: 'Potato',
      price: '₹18/kg',
      image: 'https://via.placeholder.com/200x200/FFD700/FFFFFF?text=Potato',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Potato%20-%20₹18/kg'
    },
    {
      id: 3,
      name: 'Carrot',
      price: '₹25/kg',
      image: 'https://via.placeholder.com/200x200/FF8C00/FFFFFF?text=Carrot',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Carrot%20-%20₹25/kg'
    },
    {
      id: 4,
      name: 'Cucumber',
      price: '₹15/kg',
      image: 'https://via.placeholder.com/200x200/90EE90/FFFFFF?text=Cucumber',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Cucumber%20-%20₹15/kg'
    },
    {
      id: 5,
      name: 'Spinach',
      price: '₹12/bunch',
      image: 'https://via.placeholder.com/200x200/32CD32/FFFFFF?text=Spinach',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Spinach%20-%20₹12/bunch'
    },
    {
      id: 6,
      name: 'Onion',
      price: '₹22/kg',
      image: 'https://via.placeholder.com/200x200/FF4500/FFFFFF?text=Onion',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Onion%20-%20₹22/kg'
    },
    {
      id: 7,
      name: 'Cauliflower',
      price: '₹30/pc',
      image: 'https://via.placeholder.com/200x200/9ACD32/FFFFFF?text=Cauliflower',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Cauliflower%20-%20₹30/pc'
    },
    {
      id: 8,
      name: 'Brinjal',
      price: '₹28/kg',
      image: 'https://via.placeholder.com/200x200/556B2F/FFFFFF?text=Brinjal',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Brinjal%20-%20₹28/kg'
    },
    {
      id: 9,
      name: 'Red Chilli',
      price: '₹35/kg',
      image: 'https://via.placeholder.com/200x200/FF6347/FFFFFF?text=Red%20Chilli',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Red%20Chilli%20-%20₹35/kg'
    },
    {
      id: 10,
      name: 'Cabbage',
      price: '₹20/pc',
      image: 'https://via.placeholder.com/200x200/8FBC8F/FFFFFF?text=Cabbage',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Cabbage%20-%20₹20/pc'
    },
    {
      id: 11,
      name: 'Green Peas',
      price: '₹45/kg',
      image: 'https://via.placeholder.com/200x200/228B22/FFFFFF?text=Green%20Peas',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Green%20Peas%20-%20₹45/kg'
    },
    {
      id: 12,
      name: 'Pumpkin',
      price: '₹15/kg',
      image: 'https://via.placeholder.com/200x200/FFA500/FFFFFF?text=Pumpkin',
      whatsappLink: 'https://wa.me/919876543210?text=I%20want%20to%20order%20Pumpkin%20-%20₹15/kg'
    }
  ];

  return (
    <div className="vegetables-page">
      {/* Page Header */}
      <section className="page-header bg-gradient-to-r from-fresh-green to-light-green text-white py-32 text-center">
        <div className="max-w-7xl mx-auto px-5">
          <h1 className={`text-5xl font-bold mb-4 transition-all duration-1000 transform ${
            isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
          }`}>
            Fresh Vegetables
          </h1>
          <p className="text-xl">Daily fresh vegetables directly from farms</p>
        </div>
      </section>

      {/* Vegetables Grid */}
      <section className="products-section bg-white py-16">
        <div className="max-w-7xl mx-auto px-5">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {vegetables.map((vegetable, index) => (
              <div 
                key={vegetable.id}
                className={`bg-gray-50 rounded-xl overflow-hidden transition-all transform hover:-translate-y-2 hover:shadow-xl ${
                  isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
                }`}
                style={{ transitionDelay: `${index * 50}ms` }}
              >
                <img 
                  src={vegetable.image} 
                  alt={vegetable.name} 
                  className="w-full h-48 object-cover"
                />
                <div className="p-6 text-center">
                  <h3 className="text-xl font-semibold mb-2 text-gray-800">{vegetable.name}</h3>
                  <p className="text-lg font-bold text-fresh-green mb-4">{vegetable.price}</p>
                  <a 
                    href={vegetable.whatsappLink} 
                    className="bg-whatsapp hover:bg-green-600 text-white px-4 py-2 rounded-lg font-semibold transition-all" 
                    target="_blank" 
                    rel="noopener noreferrer"
                  >
                    <i className="fab fa-whatsapp mr-2"></i> Order on WhatsApp
                  </a>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Quick Order Section */}
      <section className="quick-order bg-gray-50 py-16 text-center">
        <div className="max-w-7xl mx-auto px-5">
          <div className="quick-order-content">
            <h2 className="text-3xl font-bold mb-4 text-fresh-green">Quick Order</h2>
            <p className="text-lg mb-8 text-gray-600">Can't find what you're looking for? Message us on WhatsApp!</p>
            <a 
              href="https://wa.me/919876543210?text=Hi%20I%20want%20to%20order%20vegetables" 
              className="bg-fresh-green hover:bg-green-800 text-white px-8 py-4 rounded-lg font-semibold text-lg transition-all transform hover:-translate-y-1" 
              target="_blank" 
              rel="noopener noreferrer"
            >
              <i className="fab fa-whatsapp mr-2"></i> Order Custom Vegetables
            </a>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Vegetables;
